const eas = new EAS('0xA1207F3BBa224E2c9c3c6D5aF63D0eb1582Ce587');
eas.connect(signer);
const schemaEncoder = new SchemaEncoder('bool isKYCVerified');
const encoded = schemaEncoder.encodeData([{ name: 'isKYCVerified', value: true, type: 'bool' }]);
